import time

def social_media_tracker(platforms, thresholds):
    usage = {platform: 0 for platform in platforms}

    while True:
        print("\nCurrent usage (minutes):")
        for platform, time_spent in usage.items():
            print(f"{platform}: {time_spent}")

        platform = input("Enter platform to use (or 'quit' to exit): ").strip()
        if platform.lower() == 'quit':
            break

        if platform not in platforms:
            print("Unrecognized platform. Try again.")
            continue

        usage[platform] += int(input("Enter time spent (minutes): "))

        if usage[platform] >= thresholds[platform]:
            print(f"Warning: You've exceeded the {thresholds[platform]}-minute threshold for {platform}. Take a break!")
            usage[platform] = 0  # Reset after warning

# Example usage
platforms = ['LinkedIn', 'dev.to', 'Facebook']
thresholds = {'LinkedIn': 30, 'dev.to': 60, 'Facebook': 15}
social_media_tracker(platforms, thresholds)
